                {/* MODIFIED: Reduce padding based on layout mode */}
                <div className={`flex-1 flex flex-col min-w-0 bg-gray-50 dark:bg-slate-950 transition-all relative w-full ${isDragging ? 'ring-4 ring-indigo-500/50 scale-[0.99]' : ''} ${layoutMode === 'evidence' ? 'p-3' : 'p-4 md:p-6'}`} onDragOver={handleDragOver} onDragLeave={handleDragLeave} onDrop={handleDrop}>
                    {isDragging && (
