                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>

                                {/* MODIFIED: Buttons swapped and top border removed */}
                                <div className="flex flex-row justify-end gap-2 mt-2 items-center pt-2">
                                    <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} title={getAnalyzeTooltip()} className={`h-10 px-6 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-3 ${isReadyForAnalysis ? "btn-shrimp shadow-xl hover:scale-105 active:scale-95" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`}>
                                        {isAnalyzeLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}
                                        <span className="hidden md:inline text-xs uppercase tracking-wider">Compliance Analysis</span>
                                    </button>

                                    <button onClick={() => handleExport(evidence, 'evidence', evidenceLanguage)} className="h-10 px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center gap-2 transition-all duration-300 hover:scale-105 active:scale-95 shadow-sm" title="Export Raw Text">
                                        {isEvidenceExportLoading ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Download"/>} 
                                        <div className="lang-pill-container ml-1">
                                            <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('en');}} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                                            <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('vi');}} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                                        </div>
                                    </button>
                                </div>
                            </div>
                        )}

                        {/* 2. FINDINGS MODE */}
                        {layoutMode === 'findings' && (
                             <div className="h-full flex flex-col animate-fade-in-up">
                                <div className="flex justify-between items-center mb-2">
                                    {/* MODIFIED: Fixed height for toggle container */}
                                    <div className="h-10 bg-gray-200 dark:bg-slate-800 rounded-lg p-1 flex items-center gap-1">
                                        <button onClick={() => setFindingsViewMode('list')} className={`h-full px-3 rounded-md transition-all flex items-center justify-center ${findingsViewMode === 'list' ? 'bg-white dark:bg-slate-600 shadow-sm' : 'text-slate-400'}`}>
                                            <Icon name="LayoutList" size={16}/>
                                        </button>
                                        <button onClick={() => setFindingsViewMode('matrix')} className={`h-full px-3 rounded-md transition-all flex items-center justify-center ${findingsViewMode === 'matrix' ? 'bg-white dark:bg-slate-600 shadow-sm' : 'text-slate-400'}`}>
                                            <Icon name="Grid" size={16}/>
                                        </button>
                                    </div>

                                    {/* Removed Export Button from Header */}
                                </div>

                                {/* MODIFIED: Reduced space-y from 4 to 2 */}
                                <div ref={findingsContainerRef} className="flex-1 overflow-y-auto custom-scrollbar space-y-2 pr-1 pb-2">
                                    {/* Empty State when just started */}
                                    {(!analysisResult || analysisResult.length === 0) && !isAnalyzeLoading && (
                                        <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60 animate-in zoom-in-95 duration-500">
                                            <Icon name="Wand2" size={64} className="mb-4 text-slate-300 dark:text-slate-700"/>
                                            <p>No analysis data yet. Run analysis first.</p>
                                        </div>
                                    )}

                                    {/* Matrix View Render */}
                                    {findingsViewMode === 'matrix' && analysisResult && analysisResult.length > 0 && (
                                        // MODIFIED: Reduced Gap
                                        <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10 gap-1 p-1">
                                            {analysisResult.map((result, idx) => {
                                                const isActive = selectedFindings[result.clauseId];
                                                let bgColor = 'bg-gray-200 dark:bg-slate-700';
                                                let textColor = 'text-slate-500 dark:text-slate-400';

                                                if (isActive) {
                                                    if (result.status === 'COMPLIANT') { bgColor = 'bg-emerald-500'; textColor = 'text-white'; }
                                                    else if (result.status.includes('MAJOR')) { bgColor = 'bg-red-600'; textColor = 'text-white'; }
                                                    else if (result.status.includes('MINOR')) { bgColor = 'bg-orange-400'; textColor = 'text-white'; }
                                                    else if (result.status === 'OFI') { bgColor = 'bg-blue-500'; textColor = 'text-white'; }
                                                }

                                                return (
                                                    <div 
                                                        key={result.clauseId}
                                                        className={`aspect-square rounded-lg flex items-center justify-center text-[10px] font-bold cursor-pointer transition-all hover:scale-110 shadow-sm ${bgColor} ${textColor} ${!isActive ? 'opacity-50' : ''}`}
                                                        title={`${result.clauseId}: ${result.status}\n${result.reason}`}
                                                        onClick={() => setSelectedFindings(prev => ({...prev, [result.clauseId]: !prev[result.clauseId]}))}
                                                    >
                                                        {result.clauseId}
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    )}

                                    {/* List View Render */}
                                    {findingsViewMode === 'list' && analysisResult?.map((result, idx) => (
