                                                    {result.suggestion && <div className="mt-1 flex gap-2 items-start"><Icon name="Lightbulb" size={14} className="text-amber-500 mt-0.5"/><p className="text-xs text-slate-600 dark:text-slate-300">{result.suggestion}</p></div>}
                                                </div>
                                            </div>
                                        </div>
                                    ))}

                                    {/* Streaming/Processing Placeholder Card */}
