                                <div 
                                    className={`absolute top-1 bottom-1 rounded-lg transition-all duration-500 ease-fluid-spring z-0 ${
                                        layoutMode === 'evidence' ? 'bg-blue-600 shadow-lg shadow-blue-500/30' : 
                                        layoutMode === 'findings' ? 'bg-purple-600 shadow-lg shadow-purple-500/30' : 
                                        'bg-emerald-600 shadow-lg shadow-emerald-500/30'
