                                            className={`flex-1 relative z-10 flex items-center justify-center gap-2 px-1 md:px-4 py-2.5 rounded-lg text-xs md:text-sm font-bold transition-colors duration-300 group ${isActive ? 'text-white' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'}`}
                                            title={tab.label}
                                        >
                                            {/* Step Badge */}
                                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-black border transition-all ${isActive ? `bg-white ${activeBadgeText} border-transparent shadow-sm` : 'bg-transparent border-current opacity-50 group-hover:opacity-100'}`}>
                                                {tab.step}
                                            </div>

                                            <Icon name={tab.icon} size={16} className={`${isActive ? 'scale-110' : ''} transition-transform`}/> 

                                            {/* Text Label - Hidden on very small screens if sidebar open, otherwise visible */}
                                            <span className={`${isSidebarOpen ? 'hidden xl:inline' : 'hidden md:inline'}`}>{tab.label}</span>
                                        </button>
                                    );
                                })}
