                        <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                            <button onClick={handleRecall} className="p-2 bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-xl flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95" title="Recall Session">
                                <Icon name="History" size={18}/>
                            </button>
                            <button onClick={handleNewSession} className="p-2 bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-xl flex items-center justify-center transition-all shadow-sm hover:text-indigo-600 dark:hover:text-indigo-400 duration-300 hover:scale-105 active:scale-95" title="Start New Session">
                                <Icon name="Session4_FilePlus" size={18}/>
                            </button>
                        </div>
                    </div>

                    <div className="flex-1 overflow-hidden relative">
                        {/* 1. EVIDENCE MODE */}
                        {layoutMode === 'evidence' && (
                            <div className="h-full flex flex-col gap-2 animate-fade-in-up relative">
                                <div className="flex-1 flex flex-col gap-2 min-h-0">
                                    <div className="flex-1 bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col relative group focus-within:ring-2 ring-indigo-500/20 transition-all duration-300">
                                        <textarea 
                                            ref={evidenceTextareaRef}
                                            className="flex-1 w-full h-full p-3 bg-transparent resize-none focus:outline-none text-slate-700 dark:text-slate-300 font-mono text-sm leading-relaxed" 
                                            placeholder="Paste audit evidence here or drag & drop screenshots..." 
                                            value={evidence} 
                                            onChange={(e) => setEvidence(e.target.value)}
