                        <div className="flex-1 min-w-0">
                            {/* MODIFIED: High contrast container */}
                            <div ref={tabsContainerRef} className="relative flex justify-between bg-gray-200/80 dark:bg-slate-900 border border-gray-300 dark:border-slate-700 p-1 rounded-xl w-full overflow-hidden">
                                {/* DYNAMIC COLORED SLIDER */}
                                <div 
                                    className={`absolute top-1 bottom-1 rounded-lg transition-all duration-500 ease-fluid-spring z-0 ${
                                        layoutMode === 'evidence' ? 'bg-blue-600 shadow-lg shadow-blue-500/30' : 
                                        layoutMode === 'findings' ? 'bg-purple-600 shadow-lg shadow-purple-500/30' : 
                                        'bg-emerald-600 shadow-lg shadow-emerald-500/30'
                                    }`}
