                                            ref={el => { tabsRef.current[idx] = el; }}
                                            onClick={() => setLayoutMode(tab.id as LayoutMode)} 
                                            className={`flex-1 relative z-10 flex items-center justify-center gap-2 px-1 md:px-4 py-2.5 rounded-lg text-xs md:text-sm font-bold transition-colors duration-300 group ${isActive ? 'text-white' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'}`}
