                                <Icon name="Session4_FilePlus" size={18}/>
                            </button>
                        </div>
                    </div>

                    <div className="flex-1 overflow-hidden relative">
                        {/* 1. EVIDENCE MODE */}
                        {layoutMode === 'evidence' && (
                            <div className="h-full flex flex-col gap-2 animate-fade-in-up relative">
                                <div className="flex-1 flex flex-col gap-2 min-h-0">
                                    <div className="flex-1 bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col relative group focus-within:ring-2 ring-indigo-500/20 transition-all duration-300">
